const payload = $json;
const required = ["queue_item_id", "profile_id", "audio_url"];
const missing = required.filter((key) => !payload[key]);
if (missing.length) {
  throw new Error("Missing required fields: " + missing.join(", "));
}

const normalized = {
  ...payload,
  api_base:
    payload.api_base ||
    $env.HANA_API_BASE ||
    "http://localhost:3100/api",
  transcribe_model:
    payload.transcribe_model ||
    $env.OPENAI_TRANSCRIBE_MODEL ||
    "gpt-4o-mini-transcribe",
  structure_model:
    payload.structure_model ||
    $env.OPENAI_STRUCTURING_MODEL ||
    "gpt-4.1-mini",
  generated_at: new Date().toISOString(),
};

return [{ json: normalized }];

const apiBase = $json.api_base;

const [profilesResp, packsResp] = await Promise.all([
  fetch(apiBase + "/family-profiles"),
  fetch(apiBase + "/heritage-packs"),
]);

if (!profilesResp.ok) {
  throw new Error("Could not load family profiles: " + profilesResp.status);
}
if (!packsResp.ok) {
  throw new Error("Could not load heritage packs: " + packsResp.status);
}

const profiles = await profilesResp.json();
const packs = await packsResp.json();

const profile = (profiles || []).find((p) => p.id === $json.profile_id);
if (!profile) {
  throw new Error("Profile not found for id: " + $json.profile_id);
}

const heritagePackId = Array.isArray(profile.heritage_pack_ids) && profile.heritage_pack_ids.length
  ? profile.heritage_pack_ids[0]
  : "southeast-asian";

const heritagePack = (packs || []).find((pack) => pack.id === heritagePackId) || {
  id: heritagePackId,
  label: heritagePackId,
  style_tokens: {},
  image_prompt_fragments: [],
};

return [{
  json: {
    ...$json,
    profile,
    heritage_pack_id: heritagePackId,
    heritage_pack: heritagePack,
  },
}];

let patchStatus = null;
let patchOk = false;
let patchError = null;

try {
  const resp = await fetch(
    $json.api_base + "/story-queue/" + encodeURIComponent($json.queue_item_id),
    {
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ status: "processing" }),
    },
  );
  patchStatus = resp.status;
  patchOk = resp.ok;
  if (!resp.ok) patchError = await resp.text();
} catch (error) {
  patchError = String(error.message || error);
}

return [{
  json: {
    ...$json,
    queue_processing_patch_status: patchStatus,
    queue_processing_patch_ok: patchOk,
    queue_processing_patch_error: patchError,
  },
}];

const apiKey = $env.OPENAI_API_KEY;
if (!apiKey) {
  throw new Error("OPENAI_API_KEY is required for transcription");
}

const audioResp = await fetch($json.audio_url);
if (!audioResp.ok) {
  throw new Error("Could not download audio: " + audioResp.status + " " + $json.audio_url);
}

const audioBuffer = await audioResp.arrayBuffer();
const contentType = audioResp.headers.get("content-type") || "audio/mpeg";
const extension = contentType.includes("wav") ? "wav" : contentType.includes("ogg") ? "ogg" : "m4a";

const blob = new Blob([audioBuffer], { type: contentType });
const form = new FormData();
form.append("file", blob, "recording." + extension);
form.append("model", $json.transcribe_model);

const transcribeResp = await fetch("https://api.openai.com/v1/audio/transcriptions", {
  method: "POST",
  headers: { Authorization: "Bearer " + apiKey },
  body: form,
});

if (!transcribeResp.ok) {
  const errText = await transcribeResp.text();
  throw new Error("Transcription failed: " + transcribeResp.status + " " + errText);
}

const transcribeJson = await transcribeResp.json();
const transcript = (transcribeJson.text || transcribeJson.transcript || "").trim();
if (!transcript) {
  throw new Error("Transcription returned empty transcript");
}

return [{
  json: {
    ...$json,
    transcript,
    transcription_meta: {
      model: $json.transcribe_model,
      language: transcribeJson.language || null,
      duration_seconds: $json.duration_seconds || null,
    },
  },
}];

const apiKey = $env.OPENAI_API_KEY;
if (!apiKey) {
  throw new Error("OPENAI_API_KEY is required for fact extraction");
}

const parseOutputJson = (responseJson) => {
  if (responseJson.output_text) {
    return JSON.parse(responseJson.output_text);
  }
  const output = responseJson.output || [];
  for (const block of output) {
    for (const content of block.content || []) {
      if (content.type === "output_text" && content.text) {
        return JSON.parse(content.text);
      }
    }
  }
  throw new Error("Could not parse JSON from model response");
};

const schema = {
  type: "object",
  additionalProperties: false,
  required: ["title", "summary", "tones", "themes", "memory_moments", "speaker_hint", "audience_hint", "dedication_hint"],
  properties: {
    title: { type: "string" },
    summary: { type: "string" },
    tones: { type: "array", items: { type: "string" } },
    themes: { type: "array", items: { type: "string" } },
    memory_moments: { type: "array", items: { type: "string" } },
    speaker_hint: { type: "string" },
    audience_hint: { type: "string" },
    dedication_hint: { type: "string" },
  },
};

const body = {
  model: $json.structure_model,
  input: [
    {
      role: "system",
      content: [{
        type: "input_text",
        text: "Extract grounded narrative facts from a family voice transcript. Do not invent specifics. Return JSON only.",
      }],
    },
    {
      role: "user",
      content: [{
        type: "input_text",
        text:
          "Profile: " + JSON.stringify($json.profile) +
          "\nHeritage Pack: " + JSON.stringify($json.heritage_pack) +
          "\nTranscript: " + $json.transcript,
      }],
    },
  ],
  text: {
    format: {
      type: "json_schema",
      name: "story_facts",
      strict: true,
      schema,
    },
  },
};

const resp = await fetch("https://api.openai.com/v1/responses", {
  method: "POST",
  headers: {
    Authorization: "Bearer " + apiKey,
    "Content-Type": "application/json",
  },
  body: JSON.stringify(body),
});

if (!resp.ok) {
  const errText = await resp.text();
  throw new Error("Fact extraction failed: " + resp.status + " " + errText);
}

const responseJson = await resp.json();
const facts = parseOutputJson(responseJson);

return [{ json: { ...$json, facts } }];

const apiKey = $env.OPENAI_API_KEY;
if (!apiKey) {
  throw new Error("OPENAI_API_KEY is required for story structuring");
}

const parseOutputJson = (responseJson) => {
  if (responseJson.output_text) {
    return JSON.parse(responseJson.output_text);
  }
  const output = responseJson.output || [];
  for (const block of output) {
    for (const content of block.content || []) {
      if (content.type === "output_text" && content.text) {
        return JSON.parse(content.text);
      }
    }
  }
  throw new Error("Could not parse JSON from model response");
};

const schema = {
  type: "object",
  additionalProperties: false,
  required: ["metadata", "throughline", "dedication", "beats"],
  properties: {
    metadata: {
      type: "object",
      additionalProperties: false,
      required: ["title", "speaker", "audience", "tone", "language_tags", "heritage_tags"],
      properties: {
        title: { type: "string" },
        speaker: { type: "string" },
        audience: { type: "string" },
        tone: { type: "array", items: { type: "string" } },
        language_tags: { type: "array", items: { type: "string" } },
        heritage_tags: { type: "array", items: { type: "string" } },
      },
    },
    throughline: { type: "string" },
    dedication: { type: "string" },
    beats: {
      type: "array",
      minItems: 4,
      maxItems: 8,
      items: {
        type: "object",
        additionalProperties: false,
        required: ["kind", "theme", "experience", "title", "content", "content_origin", "visual_prompt", "ambient_detail"],
        properties: {
          kind: { type: "string" },
          theme: { type: "string" },
          experience: { type: "string" },
          title: { type: "string" },
          content: { type: "string" },
          content_origin: { type: "string" },
          visual_prompt: { type: "string" },
          ambient_detail: { type: "string" },
        },
      },
    },
  },
};

const body = {
  model: $json.structure_model,
  input: [
    {
      role: "system",
      content: [{
        type: "input_text",
        text:
          "Transform family memory transcript facts into a structured story payload. Keep details grounded in transcript. Use only experiences: memory-cards, generated-image, recipe-scroll.",
      }],
    },
    {
      role: "user",
      content: [{
        type: "input_text",
        text:
          "Transcript: " + $json.transcript +
          "\nFacts: " + JSON.stringify($json.facts) +
          "\nProfile: " + JSON.stringify($json.profile) +
          "\nHeritage Pack: " + JSON.stringify($json.heritage_pack) +
          "\nOutput must fit the provided JSON schema.",
      }],
    },
  ],
  text: {
    format: {
      type: "json_schema",
      name: "structured_story",
      strict: true,
      schema,
    },
  },
};

const resp = await fetch("https://api.openai.com/v1/responses", {
  method: "POST",
  headers: {
    Authorization: "Bearer " + apiKey,
    "Content-Type": "application/json",
  },
  body: JSON.stringify(body),
});

if (!resp.ok) {
  const errText = await resp.text();
  throw new Error("Story structuring failed: " + resp.status + " " + errText);
}

const structured = parseOutputJson(await resp.json());

const safeSlug = (value) =>
  String(value || "memory")
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/(^-|-$)/g, "")
    .slice(0, 32) || "memory";

const datePart = new Date($json.generated_at || Date.now()).toISOString().slice(0, 10);
const profileSlug = String($json.profile_id || "profile").replace(/^profile-/, "");
const titleSlug = safeSlug(structured.metadata?.title);
const storyId = "story-" + profileSlug + "-" + datePart + "-" + titleSlug;
const allowedExperiences = new Set(["memory-cards", "generated-image", "recipe-scroll"]);

const beats = (structured.beats || []).slice(0, 8).map((beat, index) => ({
  id: "beat-" + String(index + 1).padStart(3, "0"),
  kind: beat.kind || "memory",
  theme: beat.theme || "memory",
  experience: allowedExperiences.has(beat.experience) ? beat.experience : "memory-cards",
  title: beat.title || "Memory",
  content: beat.content || "",
  content_origin: beat.content_origin || beat.content || "",
  visual_prompt: beat.visual_prompt || "",
  ambient_detail: beat.ambient_detail || "",
}));

const story = {
  id: storyId,
  profile_id: $json.profile_id,
  heritage_pack_id: $json.heritage_pack_id,
  status: "complete",
  metadata: {
    title: structured.metadata?.title || $json.facts?.title || "Family Memory",
    created_at: datePart,
    created_by: "n8n workflow",
    speaker: structured.metadata?.speaker || $json.facts?.speaker_hint || $json.profile?.name || "",
    audience: structured.metadata?.audience || $json.facts?.audience_hint || "family",
    heritage_tags: structured.metadata?.heritage_tags || [$json.heritage_pack_id],
    language_tags: structured.metadata?.language_tags || $json.profile?.language_tags || ["en"],
    tone: structured.metadata?.tone || $json.facts?.tones || ["warm"],
  },
  beats,
  throughline: structured.throughline || $json.facts?.summary || "",
  dedication: structured.dedication || $json.facts?.dedication_hint || "",
};

return [{ json: { ...$json, story } }];

const story = $json.story;
const errors = [];

if (!story || typeof story !== "object") {
  errors.push("Missing story object");
} else {
  const requiredTop = ["id", "profile_id", "heritage_pack_id", "status", "metadata", "beats"];
  for (const key of requiredTop) {
    if (story[key] === undefined || story[key] === null) errors.push("Missing top-level field: " + key);
  }

  if (!Array.isArray(story.beats) || story.beats.length === 0) {
    errors.push("Story requires at least one beat");
  }

  const allowedExperiences = new Set(["memory-cards", "generated-image", "recipe-scroll"]);
  for (const [idx, beat] of (story.beats || []).entries()) {
    const requiredBeat = ["id", "kind", "theme", "experience", "title", "content"];
    for (const key of requiredBeat) {
      if (beat[key] === undefined || beat[key] === null || beat[key] === "") {
        errors.push("Beat " + (idx + 1) + " missing field: " + key);
      }
    }
    if (beat.experience && !allowedExperiences.has(beat.experience)) {
      errors.push("Beat " + (idx + 1) + " invalid experience: " + beat.experience);
    }
  }
}

return [{
  json: {
    ...$json,
    is_valid: errors.length === 0,
    validation_errors: errors,
  },
}];

let persisted = false;
let persistStatus = null;
let persistError = null;

try {
  const resp = await fetch($json.api_base + "/stories", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify($json.story),
  });
  persistStatus = resp.status;
  persisted = resp.ok;
  if (!resp.ok) persistError = await resp.text();
} catch (error) {
  persistError = String(error.message || error);
}

return [{
  json: {
    ...$json,
    persisted,
    persist_status: persistStatus,
    persist_error: persistError,
  },
}];

let patchStatus = null;
let patchOk = false;
let patchError = null;

try {
  const resp = await fetch(
    $json.api_base + "/story-queue/" + encodeURIComponent($json.queue_item_id),
    {
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ status: "complete", story_id: $json.story.id }),
    },
  );
  patchStatus = resp.status;
  patchOk = resp.ok;
  if (!resp.ok) patchError = await resp.text();
} catch (error) {
  patchError = String(error.message || error);
}

return [{
  json: {
    ...$json,
    queue_complete_patch_status: patchStatus,
    queue_complete_patch_ok: patchOk,
    queue_complete_patch_error: patchError,
  },
}];

return [{
  json: {
    ok: true,
    queue_item_id: $json.queue_item_id,
    story_id: $json.story.id,
    share_path: "/story/" + $json.story.id,
    persisted: $json.persisted,
    persist_status: $json.persist_status,
    persist_error: $json.persist_error || null,
    queue_complete_patch_ok: $json.queue_complete_patch_ok,
    queue_complete_patch_status: $json.queue_complete_patch_status,
    queue_complete_patch_error: $json.queue_complete_patch_error || null,
    validation_errors: $json.validation_errors || [],
  },
}];

let patchStatus = null;
let patchOk = false;
let patchError = null;

try {
  const resp = await fetch(
    $json.api_base + "/story-queue/" + encodeURIComponent($json.queue_item_id),
    {
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        status: "queued",
        error_note: ($json.validation_errors || []).join("; ").slice(0, 280),
      }),
    },
  );
  patchStatus = resp.status;
  patchOk = resp.ok;
  if (!resp.ok) patchError = await resp.text();
} catch (error) {
  patchError = String(error.message || error);
}

return [{
  json: {
    ...$json,
    queue_failed_patch_status: patchStatus,
    queue_failed_patch_ok: patchOk,
    queue_failed_patch_error: patchError,
  },
}];

return [{
  json: {
    ok: false,
    stage: "validate_story",
    queue_item_id: $json.queue_item_id,
    errors: $json.validation_errors || ["Unknown validation error"],
    queue_failed_patch_ok: $json.queue_failed_patch_ok,
    queue_failed_patch_status: $json.queue_failed_patch_status,
    queue_failed_patch_error: $json.queue_failed_patch_error || null,
  },
}];
